class Solution:
    def maximumValue(self, strs):
        best = 0
        for s in strs:
            is_numeric = True
            for ch in s:
                if ch < '0' or ch > '9':
                    is_numeric = False
                    break
            if is_numeric:
                v = 0
                for ch in s:
                    v = v * 10 + (ord(ch) - ord('0'))
            else:
                v = len(s)
            if v > best:
                best = v
        return best

