var maximumValue = function(strs) {
    let best = 0;
    for (const s of strs) {
        const isNumeric = /^[0-9]+$/.test(s);
        const v = isNumeric ? parseInt(s, 10) : s.length;
        if (v > best) best = v;
    }
    return best;
};
